changeSet.sql:
CREATE TABLE findings
(
	id serial,
	organization_id integer DEFAULT NULL,
	control_subcategory_id integer DEFAULT NULL,
	name character varying (255) NOT NULL DEFAULT '',
	percentage float DEFAULT NULL,
	value float DEFAULT NULL,
	CONSTRAINT pk_findings PRIMARY KEY (id)
	, CONSTRAINT fk_findings_to_control_subcategory FOREIGN KEY (control_subcategory_id) REFERENCES control_subcategories (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_findings_control_subcategory ON findings (control_subcategory_id);
CREATE INDEX i_findings_organization_name ON findings (organization_id, name);
CREATE INDEX ui_findings_organization_control_subcategory ON findings (organization_id, control_subcategory_id);
